use tokio::sync::mpsc;

#[tokio::main]
async fn main() {
    let (tx1, mut rx1) = mpsc::channel::<i32>(10);
    let (tx2, mut rx2) = mpsc::channel::<&str>(10);

    tx1.send(1).await.unwrap();
    drop(tx1);

    tokio::spawn(async move {
        tx2.send("hello").await.unwrap();
    });

    loop {
        tokio::select! {
            // Use pattern matching or if let to handle channel close
            Some(val) = rx1.recv() => println!("rx1: {}", val),
            Some(val) = rx2.recv() => println!("rx2: {}", val),
            else => {
                println!("all channels closed");
                break;
            }
        }
    }
}

