use tokio::sync::mpsc;
use tokio::time::{sleep, Duration};

async fn read_exact(rx: &mut mpsc::Receiver<u8>, buf: &mut Vec<u8>, n: usize) {
    // This future is NOT cancellation-safe: if select! drops it mid-way,
    // buf has partial data that is silently discarded next time
    while buf.len() < n {
        if let Some(byte) = rx.recv().await {
            buf.push(byte);
        } else {
            break;
        }
    }
}

#[tokio::main]
async fn main() {
    let (tx, mut rx) = mpsc::channel::<u8>(100);
    let mut buf = Vec::new();

    tokio::spawn(async move {
        for b in 0u8..10 { tx.send(b).await.unwrap(); }
    });

    // BUG: if the timeout fires before read_exact finishes, buf is left
    // with partial data and the partial read is thrown away on next select!
    tokio::select! {
        _ = read_exact(&mut rx, &mut buf, 5) => println!("read 5 bytes"),
        _ = sleep(Duration::from_millis(1)) => println!("timeout, buf={:?}", buf),
    }
}

error_message:
// No compile error. The bug: when select! drops the read_exact future
// (because the timeout fired), any bytes already pushed to buf are kept
// (the Vec mutation is visible), but the future's internal state about
// how far it got is lost. On the next call, reading starts from 0 again,
// potentially duplicating or skipping bytes.

fixed_code:
use tokio::sync::mpsc;
use tokio::time::{sleep, Duration};

#[tokio::main]
async fn main() {
    let (tx, mut rx) = mpsc::channel::<u8>(100);

    tokio::spawn(async move {
        for b in 0u8..10 { tx.send(b).await.unwrap(); }
    });

    let mut buf = Vec::new();

    // Cancellation-safe pattern: only ONE await point, and it's recv() which
    // is documented as cancellation-safe (if dropped before completing, no
    // message is lost — it's re-queued).
    loop {
        tokio::select! {
            Some(byte) = rx.recv() => {
                buf.push(byte);
                if buf.len() >= 5 { break; }
            }
            _ = sleep(Duration::from_millis(50)) => {
                println!("timeout after {} bytes: {:?}", buf.len(), buf);
                break;
            }
        }
    }
    println!("buf: {:?}", buf);
}

