use tokio::sync::oneshot;

#[tokio::main]
async fn main() {
    let (task_tx, mut task_rx) = mpsc::channel::<i32>(10);
    let (shutdown_tx, mut shutdown_rx) = oneshot::channel::<()>();

    // Simulate sending tasks and a shutdown signal
    for i in 0..5 { task_tx.try_send(i).unwrap(); }
    shutdown_tx.send(()).unwrap();

    // BUG: without `biased`, select! picks arms pseudo-randomly.
    // The shutdown branch might not be checked first, so we might
    // process tasks even after shutdown was requested.
    loop {
        tokio::select! {
            _ = &mut shutdown_rx => {
                println!("shutdown received, stopping");
                break;
            }
            Some(task) = task_rx.recv() => {
                println!("processing task {}", task);
            }
            else => break,
        }
    }
}

error_message:
// No compile error. The issue: without `biased`, tokio::select! randomly
// chooses which ready branch to execute. Even if shutdown_rx is ready,
// the task branch might be chosen first, processing extra tasks after
// shutdown was already signalled.

fixed_code:
use tokio::sync::mpsc;
use tokio::sync::oneshot;

#[tokio::main]
async fn main() {
    let (task_tx, mut task_rx) = mpsc::channel::<i32>(10);
    let (shutdown_tx, mut shutdown_rx) = oneshot::channel::<()>();

    for i in 0..5 { task_tx.try_send(i).unwrap(); }
    shutdown_tx.send(()).unwrap();

    loop {
        tokio::select! {
            biased;  // check branches in declaration order: shutdown first

            _ = &mut shutdown_rx => {
                println!("shutdown received, stopping");
                break;
            }
            Some(task) = task_rx.recv() => {
                println!("processing task {}", task);
            }
            else => break,
        }
    }
}

